    /**
     * OAuth access token request
     * @description Describes the valid schema for possible OAuth access token requests.
     */
    OauthAccessTokenRequest: {
      /** @enum {string} */
      grant_type: "authorization_code" | "refresh_token" | "client_credentials";
    };
    /**
     * authorization_code
     * @description A request to exchange an authorization code for an access token.
     */
    OauthAccessTokenRequestCode: {
      /** @enum {string} */
      grant_type: "authorization_code" | "refresh_token" | "client_credentials";
    } & {
      code: string;
      redirect_uri: string;
    };
    /**
     * refresh_token
     * @description A request to exchange a refresh token for a new access token.
     */
    OauthAccessTokenRequestRefresh: {
      /** @enum {string} */
      grant_type: "authorization_code" | "refresh_token" | "client_credentials";
    } & {
      refresh_token: string;
      scope?: string;
    };
    /**
     * client_credentials
     * @description A request to receive a client token.
     */
    OauthAccessTokenRequestClientCredentials: {
      /** @enum {string} */
      grant_type: "authorization_code" | "refresh_token" | "client_credentials";
    } & {
      scope: string;
    };
    /**
     * OAuth access token response
     * @description A successful OAuth access token response.
     */
    OauthAccessTokenResponse: {
      access_token: string;
      expires_in: number;
      /** @enum {string} */
      response_type?: "authorization_code" | "refresh_token" | "client_credentials";
      scope: string;
      /** @default bearer */
      token_type: string;
    };
    /**
     * OAuth access token response
     * @description A successful OAuth access token response for the authorization code flow.
     */
    OauthAccessTokenResponseCode: {
      access_token: string;
      expires_in: number;
      /** @enum {string} */
      response_type?: "authorization_code" | "refresh_token" | "client_credentials";
      scope: string;
      /** @default bearer */
      token_type: string;
    } & {
      refresh_token?: string;
      refresh_token_expires_at?: number;
      refresh_token_expires_in?: number;
    };
    /**
     * OAuth access token response
     * @description A successful OAuth access token response for the refresh token flow, with an added refresh token.
     */
    OauthAccessTokenResponseIntegrationRefresh: {
      access_token: string;
      expires_in: number;
      /** @enum {string} */
      response_type?: "authorization_code" | "refresh_token" | "client_credentials";
      scope: string;
      /** @default bearer */
      token_type: string;
    } & {
      refresh_token: string;
      refresh_token_expires_in: number;
    };
    /** @description Describes the valid schema for token revocation requests. */
    TokenRevocationRequest: {
      /**
       * @description The token to revoke.
       * @example pinr.eyJhbGciOiJS...
       */
      token: string;
      /**
       * @description The type of the token to revoke. Please refer to [our developer guide for more information](https://developers.pinterest.com/docs/getting-started/set-up-authentication-and-authorization/) for more information.
       * @enum {string}
       */
      token_type_hint?: "access_token" | "refresh_token";
    };
    /**
     * OAuth access token response
     * @description A successful OAuth access token response for the refresh token flow.
     */
    OauthAccessTokenResponseRefresh: {
      access_token: string;
      expires_in: number;
      /** @enum {string} */
      response_type?: "authorization_code" | "refresh_token" | "client_credentials";
      scope: string;
      /** @default bearer */
      token_type: string;
    } & {
      refresh_token: string;
      refresh_token_expires_at: number;
      refresh_token_expires_in: number;
    };
    /**
     * OAuth client token response
     * @description A successful OAuth client token response for the client token flow.
     */
    OauthAccessTokenResponseClientCredentials: {
      access_token: string;
      expires_in: number;
      /** @enum {string} */
      response_type?: "authorization_code" | "refresh_token" | "client_credentials";
      scope: string;
      /** @default bearer */
      token_type: string;
    };
    /**
     * @description Intended result of the campaign.
     *     You can only update objectives for draft campaigns.
     *     `WEB_SESSIONS` and `VIDEO_VIEW` objectives are deprecated. We recommend using `VIDEO_COMPLETION` as an alternative for the latter.
     * @enum {string}
     */
    ObjectiveType:
      | "AWARENESS"
